patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 2a1218a683ca..f877cf1c73ba 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -2522,6 +2522,16 @@ static Value *simplifyOrInst(Value *Op0, Value *Op1, const SimplifyQuery &Q,
       if (*Implied == true)
         return ConstantInt::getTrue(Op1->getType());
     }
+    if (std::optional<bool> Implied = isImpliedCondition(Op1, Op0, Q.DL)) {
+      // If Op1 is true implies Op0 is true, then Op1 is a subset of Op0.
+      if (*Implied == true)
+        return Op0;
+    }
+    if (std::optional<bool> Implied = isImpliedCondition(Op0, Op1, Q.DL)) {
+      // If Op0 is true implies Op1 is true, then Op0 is a subset of Op1.
+      if (*Implied == true)
+        return Op1;
+    }
   }

   if (Value *V = simplifyByDomEq(Instruction::Or, Op0, Op1, Q, MaxRecurse))
diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 973943790c0a..e846e2788560 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -8209,6 +8209,14 @@ isImpliedCondOperands(CmpInst::Predicate Pred, const Value *ALHS,
     if (isTruePredicate(CmpInst::ICMP_ULE, BLHS, ALHS, DL, Depth) &&
         isTruePredicate(CmpInst::ICMP_ULE, ARHS, BRHS, DL, Depth))
       return true;
+    // icmp ult (add X, Y), X implies icmp ult (add X, Y), Y because
+    // both are true exactly when the addition has unsigned overflow.
+    if (Pred == CmpInst::ICMP_ULT && ALHS == BLHS &&
+        match(ALHS, m_Add(m_Specific(ARHS), m_Specific(BRHS))))
+      return true;
+    if (Pred == CmpInst::ICMP_ULT && ALHS == BLHS &&
+        match(ALHS, m_Add(m_Specific(BRHS), m_Specific(ARHS))))
+      return true;
     return std::nullopt;

   case CmpInst::ICMP_UGT:
